10	const BASE_PREMIUM: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	};
17	
18	const PROCESSING_FEE = 5;
19	
20	const COMPONENT_TYPES = ["rune"];
21	const BLOCK_SIZE = 3;
22	const BLOCK_PREMIUM = 60;
23	
24	export function quote(items: Item[], customer: CustomerContext): number {
25	  const counts: Record<string, number> = {};
26	  for (const item of items) {
27	    counts[item.type] = (counts[item.type] ?? 0) + 1;
28	  }
29	
30	  let premium = 0;
31	  for (const [type, count] of Object.entries(counts)) {
32	    if (COMPONENT_TYPES.includes(type) && count === BLOCK_SIZE) {
33	      premium += BLOCK_PREMIUM;
34	    } else {
35	      premium += count * (BASE_PREMIUM[type] ?? 0);
36	    }
37	  }
38	
39	  return premium + PROCESSING_FEE;
40	}
